css:
* {
  box-sizing: border-box !important;
}

html, body {
  min-height: 100vh !important;
  background: #0a0510 !important;
  color: #f0d8e8 !important;
  font-family: 'Arial Black', 'Impact', 'Segoe UI', sans-serif !important;
}

/* Тёмный фон с оттенками ночного города */
body::before {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  background: 
    radial-gradient(circle at 30% 20%, rgba(255, 77, 109, 0.08) 0%, transparent 50%),
    radial-gradient(circle at 70% 80%, rgba(0, 212, 255, 0.06) 0%, transparent 50%),
    linear-gradient(180deg, #0a0510 0%, #1a0a20 50%, #0a0510 100%);
  background-blend-mode: overlay !important;
}

/* ===== СЛОЙ ДОЖДЯ И ЭФФЕКТОВ ===== */
#vice-rain-canvas {
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: 1 !important;
  pointer-events: none !important;
  background: transparent !important;
}

.p-pageWrapper,
.p-body,
.p-body-inner,
.p-body-main,
.p-body-content,
.p-body-pageContent,
.p-body-header,
.pageContent,
.p-body-inner {
  background: transparent !important;
}

/* Основной контейнер — стекло с лёгким туманом */
.p-body-inner {
  background: rgba(10, 5, 16, 0.65) !important;
  backdrop-filter: blur(12px) !important;
  -webkit-backdrop-filter: blur(12px) !important;
  border-radius: 36px !important;
  padding: 24px !important;
  box-shadow: 0 8px 48px rgba(0, 0, 0, 0.8), inset 0 0 80px rgba(255, 77, 109, 0.05), 0 0 0 1px rgba(255, 77, 109, 0.1) !important;
  border: none !important;
  margin: 16px auto !important;
  position: relative;
  z-index: 3;
  overflow: hidden;
}

.p-body-inner::before {
  content: '' !important;
  position: absolute !important;
  top: -2px !important;
  left: -2px !important;
  right: -2px !important;
  bottom: -2px !important;
  border-radius: 38px !important;
  background: 
    linear-gradient(135deg, rgba(255, 77, 109, 0.06), transparent 40%, transparent 60%, rgba(0, 212, 255, 0.06)) !important;
  z-index: -1 !important;
  pointer-events: none !important;
}

.p-header {
  background: rgba(10, 5, 16, 0.6) !important;
  backdrop-filter: blur(8px) !important;
  border-bottom: 1px solid rgba(255, 77, 109, 0.12) !important;
  border-radius: 36px 36px 0 0 !important;
  padding: 12px 24px !important;
  box-shadow: 0 4px 30px rgba(0,0,0,0.5) !important;
}

.p-header-logo a {
  color: #ff4d6d !important;
  font-weight: 900 !important;
  letter-spacing: 2px !important;
  text-shadow: 0 0 40px rgba(255, 77, 109, 0.4), 0 0 80px rgba(255, 77, 109, 0.15) !important;
  font-family: 'Arial Black', 'Impact', sans-serif !important;
  font-size: 1.4em !important;
}

.p-header-logo a:hover {
  text-shadow: 0 0 60px rgba(255, 77, 109, 0.6), 0 0 120px rgba(255, 77, 109, 0.3) !important;
}

.p-nav {
  background: rgba(10, 5, 16, 0.7) !important;
  backdrop-filter: blur(12px) !important;
  border-bottom: 1px solid rgba(255, 77, 109, 0.08) !important;
  box-shadow: 0 4px 32px rgba(0,0,0,0.6) !important;
  padding: 0 16px !important;
}

.p-nav-inner {
  background: transparent !important;
}

.p-nav-list {
  display: flex !important;
  gap: 4px !important;
  background: transparent !important;
}

.p-nav-list .p-navEl {
  color: #d4b8d0 !important;
  font-weight: 700 !important;
  padding: 12px 20px !important;
  border-radius: 40px !important;
  transition: all 0.3s ease !important;
  background: transparent !important;
  font-family: 'Arial Black', 'Impact', sans-serif !important;
  position: relative;
  text-transform: uppercase;
  font-size: 0.9em !important;
  letter-spacing: 1px;
}

.p-nav-list .p-navEl::after {
  content: '' !important;
  position: absolute !important;
  bottom: 6px !important;
  left: 20% !important;
  right: 20% !important;
  height: 2px !important;
  background: rgba(255, 77, 109, 0) !important;
  transition: all 0.3s ease !important;
}

.p-nav-list .p-navEl:hover::after {
  background: rgba(255, 77, 109, 0.5) !important;
  left: 10% !important;
  right: 10% !important;
}

.p-nav-list .p-navEl:hover {
  background: rgba(255, 77, 109, 0.1) !important;
  color: #ff9eb0 !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 0 30px rgba(255, 77, 109, 0.06) !important;
  text-shadow: 0 0 20px rgba(255, 77, 109, 0.15) !important;
}

.p-nav-list .p-navEl.is-selected {
  background: rgba(255, 77, 109, 0.12) !important;
  color: #ffb3c6 !important;
  box-shadow: inset 0 0 0 1px rgba(255, 77, 109, 0.15) !important;
  text-shadow: 0 0 20px rgba(255, 77, 109, 0.15) !important;
}

.p-nav-list .p-navEl.is-selected::after {
  background: rgba(255, 77, 109, 0.7) !important;
  left: 10% !important;
  right: 10% !important;
}

.p-nav-opposite {
  background: transparent !important;
}

.p-navgroup {
  background: transparent !important;
}

.p-navgroup-link {
  color: #b8a0b8 !important;
  transition: all 0.2s !important;
  text-transform: uppercase;
  font-weight: 600;
}

.p-navgroup-link:hover {
  color: #ff9eb0 !important;
  background: rgba(255, 77, 109, 0.06) !important;
  border-radius: 40px !important;
  text-shadow: 0 0 20px rgba(255, 77, 109, 0.08) !important;
}

/* Блоки — глянцевые, с намёком на мокрое стекло */
.block {
  background: rgba(20, 10, 30, 0.45) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  border-radius: 28px !important;
  border: 1px solid rgba(255, 77, 109, 0.06) !important;
  box-shadow: 0 4px 24px rgba(0,0,0,0.5), inset 0 0 60px rgba(255, 77, 109, 0.02) !important;
  padding: 20px !important;
  margin-bottom: 24px !important;
  transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) !important;
  position: relative;
  overflow: hidden;
}

.block::before {
  content: '' !important;
  position: absolute !important;
  top: -2px !important;
  left: -2px !important;
  right: -2px !important;
  bottom: -2px !important;
  border-radius: 30px !important;
  background: 
    linear-gradient(135deg, rgba(255, 77, 109, 0.04), transparent 40%, transparent 60%, rgba(0, 212, 255, 0.04)) !important;
  pointer-events: none !important;
  z-index: 0 !important;
}

.block:hover {
  box-shadow: 0 8px 40px rgba(0,0,0,0.7), inset 0 0 60px rgba(255, 77, 109, 0.04) !important;
  transform: translateY(-2px) !important;
  border-color: rgba(255, 77, 109, 0.12) !important;
}

.block-container {
  background: transparent !important;
  border: none !important;
}

.block-body {
  background: transparent !important;
}

.block-minorHeader {
  color: #ff4d6d !important;
  font-weight: 700 !important;
  padding: 12px 16px !important;
  border-bottom: 1px solid rgba(255, 77, 109, 0.06) !important;
  text-shadow: 0 0 20px rgba(255, 77, 109, 0.15) !important;
  font-family: 'Arial Black', 'Impact', sans-serif !important;
  letter-spacing: 1px;
  text-transform: uppercase;
}

.node {
  background: rgba(20, 12, 30, 0.4) !important;
  border-radius: 24px !important;
  border: 1px solid rgba(255, 77, 109, 0.04) !important;
  padding: 16px 20px !important;
  margin-bottom: 8px !important;
  transition: all 0.3s ease !important;
  position: relative;
}

.node:hover {
  background: rgba(30, 18, 44, 0.6) !important;
  border-color: rgba(255, 77, 109, 0.12) !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 8px 30px rgba(0,0,0,0.5) !important;
}

.node-title a {
  color: #f0d8e8 !important;
  font-weight: 700 !important;
  text-shadow: 0 0 10px rgba(255, 77, 109, 0.04) !important;
}

.node-title a:hover {
  color: #ffb3c6 !important;
  text-shadow: 0 0 30px rgba(255, 77, 109, 0.2) !important;
}

.node-stats {
  color: #b090b8 !important;
}

.node-extra {
  color: #b090b8 !important;
}

.node-extra-title {
  color: #c8a8c8 !important;
}

.node-extra-title:hover {
  color: #e8c8d8 !important;
}

.uix_newIndicator {
  background: rgba(255, 77, 109, 0.12) !important;
  color: #ff9eb0 !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  text-shadow: 0 0 10px rgba(255, 77, 109, 0.15) !important;
}

.node-body {
  background: transparent !important;
  display: flex !important;
  align-items: center !important;
  flex-wrap: wrap !important;
  gap: 8px !important;
}

.structItem {
  background: rgba(18, 10, 28, 0.35) !important;
  border-radius: 20px !important;
  border: 1px solid rgba(255, 77, 109, 0.04) !important;
  padding: 12px 16px !important;
  margin-bottom: 6px !important;
  transition: all 0.25s ease !important;
  display: flex !important;
  align-items: stretch !important;
  flex-wrap: nowrap !important;
  gap: 12px !important;
}

.structItem:hover {
  background: rgba(26, 16, 40, 0.5) !important;
  border-color: rgba(255, 77, 109, 0.1) !important;
  box-shadow: 0 4px 20px rgba(0,0,0,0.4) !important;
}

.structItem-cell {
  display: flex !important;
  align-items: center !important;
}

.structItem-cell--icon {
  flex: 0 0 48px !important;
  min-width: 48px !important;
  justify-content: center !important;
}

.structItem-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  flex-direction: column !important;
  align-items: stretch !important;
}

.structItem-cell--meta {
  flex: 0 0 100px !important;
  justify-content: center !important;
  align-items: flex-start !important;
}

.structItem-cell--latest {
  flex: 0 0 120px !important;
  justify-content: center !important;
  align-items: flex-end !important;
  text-align: right !important;
}

.structItem-cell--iconEnd {
  flex: 0 0 32px !important;
  justify-content: center !important;
}

.structItem-title {
  color: #f0d8e8 !important;
  font-weight: 600 !important;
}

.structItem-title a {
  color: #f0d8e8 !important;
}

.structItem-title a:hover {
  color: #ffb3c6 !important;
  text-shadow: 0 0 30px rgba(255, 77, 109, 0.15) !important;
}

.structItem-statuses {
  color: #b090b8 !important;
  display: flex !important;
  gap: 4px !important;
  align-items: center !important;
}

.structItem-status--locked {
  color: #ff8888 !important;
}

.structItem-status--sticky {
  color: #f0c080 !important;
}

.structItem-minor {
  color: #9890b0 !important;
  font-size: 13px !important;
}

.structItem-minor a {
  color: #b090b8 !important;
}

.structItem-minor a:hover {
  color: #d0b8d8 !important;
}

.structItem-parts {
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  margin: 0 !important;
  padding: 0 !important;
  list-style: none !important;
}

.structItem-parts li {
  display: inline !important;
}

.structItem-latestDate {
  color: #b090b8 !important;
}

.structItem--quickCreate {
  background: rgba(18, 10, 28, 0.25) !important;
  border: 1px dashed rgba(255, 77, 109, 0.12) !important;
  border-radius: 20px !important;
}

.structItem--quickCreate textarea {
  background: rgba(8, 4, 16, 0.5) !important;
  border: 1px solid rgba(255, 77, 109, 0.08) !important;
  color: #f0d8e8 !important;
  border-radius: 20px !important;
  padding: 12px !important;
}

.structItem--quickCreate textarea:focus {
  border-color: rgba(255, 77, 109, 0.25) !important;
  box-shadow: 0 0 0 4px rgba(255, 77, 109, 0.04) !important;
}

.message {
  background: rgba(20, 12, 30, 0.45) !important;
  backdrop-filter: blur(6px) !important;
  -webkit-backdrop-filter: blur(6px) !important;
  border-radius: 28px !important;
  border: 1px solid rgba(255, 77, 109, 0.04) !important;
  padding: 0 !important;
  margin-bottom: 20px !important;
  transition: all 0.3s ease !important;
  overflow: hidden !important;
  position: relative;
}

.message:hover {
  background: rgba(28, 18, 44, 0.55) !important;
  border-color: rgba(255, 77, 109, 0.12) !important;
  box-shadow: 0 8px 32px rgba(0,0,0,0.5) !important;
  transform: translateY(-2px) !important;
}

.message-inner {
  background: transparent !important;
  display: flex !important;
  flex-wrap: wrap !important;
}

.message-cell {
  background: transparent !important;
  padding: 16px !important;
}

.message-cell--user {
  background: rgba(12, 6, 20, 0.25) !important;
  border-right: 1px solid rgba(255, 77, 109, 0.04) !important;
  border-radius: 28px 0 0 20px !important;
  min-width: 180px !important;
  flex: 0 0 180px !important;
}

.message-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  border-radius: 0 28px 20px 0 !important;
}

.message-user {
  background: transparent !important;
}

.message-avatar {
  text-align: center !important;
  margin-bottom: 8px !important;
}

.message-avatar .avatar {
  border-radius: 50% !important;
  border: 2px solid rgba(255, 77, 109, 0.15) !important;
  transition: all 0.3s ease !important;
  box-shadow: 0 0 20px rgba(255, 77, 109, 0.04) !important;
}

.message-avatar .avatar:hover {
  transform: scale(1.08) !important;
  border-color: rgba(255, 77, 109, 0.35) !important;
  box-shadow: 0 0 40px rgba(255, 77, 109, 0.12) !important;
}

.message-userDetails {
  text-align: center !important;
}

.message-name {
  font-weight: 700 !important;
  font-size: 15px !important;
  font-family: 'Arial Black', 'Impact', sans-serif !important;
}

.message-name a {
  color: #f0d8e8 !important;
}

.message-name a:hover {
  color: #ffb3c6 !important;
  text-shadow: 0 0 30px rgba(255, 77, 109, 0.15) !important;
}

.userBanner {
  background: rgba(255, 77, 109, 0.06) !important;
  border-radius: 40px !important;
  padding: 2px 14px !important;
  font-size: 11px !important;
  color: #c8a8c8 !important;
  display: inline-block !important;
  margin-top: 4px !important;
  text-shadow: 0 0 10px rgba(255, 77, 109, 0.04) !important;
}

.userBanner--red {
  background: rgba(200, 80, 80, 0.12) !important;
  color: #ff8888 !important;
}

.userBanner--primary {
  background: rgba(255, 77, 109, 0.06) !important;
  color: #c8a8c8 !important;
}

.message-userExtras {
  margin-top: 8px !important;
  font-size: 12px !important;
  color: #9890b0 !important;
}

.message-userExtras .pairs {
  padding: 2px 0 !important;
}

.message-userExtras .pairs dt {
  color: #706888 !important;
}

.message-userExtras .pairs dd {
  color: #b8a0c0 !important;
}

.message-attribution {
  background: rgba(8, 4, 16, 0.15) !important;
  padding: 8px 16px !important;
  border-bottom: 1px solid rgba(255, 77, 109, 0.03) !important;
}

.message-attribution a {
  color: #9890b0 !important;
}

.message-attribution a:hover {
  color: #c8a8c8 !important;
}

.message-newIndicator {
  background: rgba(255, 77, 109, 0.1) !important;
  color: #ff9eb0 !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  text-shadow: 0 0 10px rgba(255, 77, 109, 0.15) !important;
}

.message-content {
  padding: 16px !important;
}

.message-body {
  color: #e8d8e8 !important;
  font-size: 15px !important;
  line-height: 1.7 !important;
}

.message-body .bbWrapper {
  color: #e8d8e8 !important;
}

.message-body a {
  color: #ff9eb0 !important;
}

.message-body a:hover {
  color: #ffb3c6 !important;
  text-shadow: 0 0 30px rgba(255, 77, 109, 0.15) !important;
}

.message-body .bbMediaWrapper {
  border-radius: 20px !important;
  overflow: hidden !important;
  background: rgba(8, 4, 16, 0.5) !important;
  border: 1px solid rgba(255, 77, 109, 0.06) !important;
}

.message-body .bbMediaWrapper iframe {
  border-radius: 20px !important;
}

.message-fields--before {
  background: rgba(12, 6, 20, 0.25) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  margin-bottom: 12px !important;
  border: 1px solid rgba(255, 77, 109, 0.04) !important;
}

.message-fields--before .pairs {
  padding: 2px 0 !important;
}

.message-fields--before .pairs dt {
  color: #706888 !important;
  font-weight: 500 !important;
}

.message-fields--before .pairs dd {
  color: #c8a8c8 !important;
}

.message-signature {
  background: rgba(8, 4, 16, 0.12) !important;
  border-top: 1px solid rgba(255, 77, 109, 0.03) !important;
  padding: 12px 16px !important;
  margin-top: 12px !important;
  border-radius: 0 0 20px 20px !important;
  font-size: 13px !important;
  color: #9890b0 !important;
  max-height: 100px !important;
  overflow: hidden !important;
  transition: max-height 0.3s ease !important;
}

.message-signature--expanded {
  max-height: 500px !important;
}

.message-signature .bbWrapper {
  color: #9890b0 !important;
}

.message-signature a {
  color: #a888b8 !important;
}

.message-signature a:hover {
  color: #c8a8d8 !important;
}

.uix_signatureExpand {
  cursor: pointer !important;
  color: #706888 !important;
  font-size: 11px !important;
  text-align: center !important;
  padding: 4px !important;
  border-radius: 40px !important;
  background: rgba(255, 77, 109, 0.03) !important;
  margin-bottom: 6px !important;
  transition: all 0.2s !important;
}

.uix_signatureExpand:hover {
  background: rgba(255, 77, 109, 0.06) !important;
  color: #c8a8c8 !important;
}

.actionBar {
  background: rgba(8, 4, 16, 0.15) !important;
  border-top: 1px solid rgba(255, 77, 109, 0.03) !important;
  padding: 6px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  border-radius: 0 0 20px 20px !important;
}

.actionBar-action {
  background: transparent !important;
  color: #9890b0 !important;
  padding: 4px 12px !important;
  border-radius: 40px !important;
  font-size: 13px !important;
  transition: all 0.2s !important;
  cursor: pointer !important;
}

.actionBar-action:hover {
  background: rgba(255, 77, 109, 0.06) !important;
  color: #d0b8d0 !important;
}

.actionBar-action--reaction {
  background: rgba(255, 77, 109, 0.03) !important;
}

.actionBar-action--reaction:hover {
  background: rgba(255, 77, 109, 0.1) !important;
}

.actionBar-action--menuTrigger {
  color: #706888 !important;
}

.actionBar-action--menuTrigger:hover {
  background: rgba(255, 77, 109, 0.04) !important;
}

.blockStatus {
  background: rgba(16, 8, 24, 0.5) !important;
  border-radius: 40px !important;
  border: 1px solid rgba(255, 77, 109, 0.08) !important;
  padding: 8px 24px !important;
  color: #c8a8c8 !important;
  backdrop-filter: blur(4px) !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 8px !important;
}

.blockStatus-message {
  color: #c8a8c8 !important;
}

.blockStatus-message--locked {
  border-color: #cc6666 !important;
  color: #ff8888 !important;
  background: rgba(200, 80, 80, 0.06) !important;
  border-radius: 40px !important;
  padding: 4px 16px !important;
}

.message-newIndicator,
.uix_newIndicator {
  background: rgba(255, 77, 109, 0.1) !important;
  color: #ff9eb0 !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  font-weight: 700 !important;
  text-shadow: 0 0 10px rgba(255, 77, 109, 0.15) !important;
}

.message--deleted {
  opacity: 0.5 !important;
  background: rgba(200, 80, 80, 0.04) !important;
  border-color: rgba(200, 80, 80, 0.06) !important;
}

.messageNotice--deleted {
  background: rgba(200, 80, 80, 0.03) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  color: #ff8888 !important;
}

.messageNotice--deleted a {
  color: #ff8888 !important;
}

.messageNotice--deleted a:hover {
  color: #ffaaaa !important;
}

.reactionsBar {
  background: rgba(8, 4, 16, 0.15) !important;
  border-radius: 40px !important;
  padding: 4px 12px !important;
  margin: 0 16px 8px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 2px !important;
  min-height: 28px !important;
}

.reaction {
  background: rgba(255, 77, 109, 0.04) !important;
  border-radius: 40px !important;
  padding: 2px 8px !important;
  transition: all 0.2s !important;
}

.reaction:hover {
  background: rgba(255, 77, 109, 0.1) !important;
  transform: scale(1.05) !important;
}

.reaction-image--emoji {
  width: 20px !important;
  height: 20px !important;
  border-radius: 50% !important;
}

.reactionSummary {
  background: rgba(16, 8, 24, 0.35) !important;
  border-radius: 40px !important;
  padding: 2px 10px !important;
