(function() {
  // ===== ДОЖДЛИВАЯ НОЧЬ В МАЙАМИ =====
  function initViceRain() {
    const canvas = document.createElement('canvas');
    canvas.id = 'vice-rain-canvas';
    canvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;z-index:1;pointer-events:none;background:transparent;';
    document.body.appendChild(canvas);

    const ctx = canvas.getContext('2d');
    let W, H;
    let time = 0;

    function resize() {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    }
    window.addEventListener('resize', resize);
    resize();

    // ===== КАПЛИ ДОЖДЯ =====
    const raindrops = [];
    for (let i = 0; i < 250; i++) {
      raindrops.push({
        x: Math.random() * W,
        y: Math.random() * H,
        length: 10 + Math.random() * 20,
        speed: 8 + Math.random() * 12,
        opacity: 0.2 + Math.random() * 0.3,
        width: 0.5 + Math.random() * 1
      });
    }

    // ===== ОТРАЖЕНИЯ НЕОНА НА АСФАЛЬТЕ (размытые пятна) =====
    const reflections = [
      { x: 0.15, y: 0.85, color: 'rgba(255, 77, 109, 0.08)', radius: 200 },
      { x: 0.45, y: 0.9, color: 'rgba(0, 212, 255, 0.06)', radius: 180 },
      { x: 0.75, y: 0.8, color: 'rgba(255, 158, 94, 0.07)', radius: 220 },
      { x: 0.35, y: 0.75, color: 'rgba(167, 139, 250, 0.05)', radius: 150 },
    ];

    // ===== ТУМАН (слои) =====
    const fogLayers = [];
    for (let i = 0; i < 4; i++) {
      fogLayers.push({
        yOffset: 0.6 + i * 0.1,
        speed: 0.1 + Math.random() * 0.2,
        opacity: 0.02 + Math.random() * 0.03,
        width: 0.3 + Math.random() * 0.4,
      });
    }

    // ===== КАПЛИ НА СТЕКЛЕ (крупные) =====
    const glassDrops = [];
    for (let i = 0; i < 8; i++) {
      glassDrops.push({
        x: Math.random() * W,
        y: Math.random() * H,
        radius: 3 + Math.random() * 6,
        speed: 0.2 + Math.random() * 0.4,
        opacity: 0.1 + Math.random() * 0.15,
        phase: Math.random() * Math.PI * 2,
        // для эффекта стекания
        trail: []
      });
    }

    function drawRain() {
      for (const drop of raindrops) {
        drop.y += drop.speed;
        if (drop.y > H + 20) {
          drop.y = -20;
          drop.x = Math.random() * W;
        }
        ctx.beginPath();
        ctx.moveTo(drop.x, drop.y);
        ctx.lineTo(drop.x + 0.5, drop.y + drop.length);
        ctx.strokeStyle = `rgba(180, 200, 255, ${drop.opacity})`;
        ctx.lineWidth = drop.width;
        ctx.shadowColor = 'rgba(180, 200, 255, 0.1)';
        ctx.shadowBlur = 5;
        ctx.stroke();
      }
      ctx.shadowBlur = 0;
    }

    function drawReflections() {
      for (const ref of reflections) {
        const gradient = ctx.createRadialGradient(
          ref.x * W, ref.y * H, 0,
          ref.x * W, ref.y * H, ref.radius
        );
        gradient.addColorStop(0, ref.color);
        gradient.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = gradient;
        ctx.beginPath();
        ctx.arc(ref.x * W, ref.y * H, ref.radius, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    function drawFog() {
      for (const layer of fogLayers) {
        const offset = (time * layer.speed * 0.01) % W;
        ctx.fillStyle = `rgba(20, 30, 50, ${layer.opacity})`;
        ctx.fillRect(-offset, H * layer.yOffset, W * 1.5, H * 0.3);
        ctx.fillRect(offset - W * 0.3, H * layer.yOffset + 10, W * 0.8, H * 0.2);
      }
    }

    function drawGlassDrops() {
      for (const drop of glassDrops) {
        drop.y += drop.speed;
        if (drop.y > H + 20) {
          drop.y = -20;
          drop.x = Math.random() * W;
        }
        // Основная капля (размытая)
        ctx.beginPath();
        ctx.arc(drop.x, drop.y, drop.radius, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${drop.opacity})`;
        ctx.shadowColor = 'rgba(200, 220, 255, 0.1)';
        ctx.shadowBlur = 10;
        ctx.fill();
        // Световой блик
        ctx.beginPath();
        ctx.arc(drop.x - drop.radius * 0.3, drop.y - drop.radius * 0.3, drop.radius * 0.2, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${drop.opacity * 0.6})`;
        ctx.shadowBlur = 0;
        ctx.fill();
        // Маленький хвост (стекание)
        ctx.beginPath();
        ctx.moveTo(drop.x - drop.radius * 0.4, drop.y + drop.radius * 0.2);
        ctx.quadraticCurveTo(drop.x, drop.y + drop.radius * 1.2, drop.x + drop.radius * 0.4, drop.y + drop.radius * 0.2);
        ctx.fillStyle = `rgba(255, 255, 255, ${drop.opacity * 0.3})`;
        ctx.fill();
      }
      ctx.shadowBlur = 0;
    }

    function draw() {
      time++;
      ctx.clearRect(0, 0, W, H);

      drawReflections();   // сначала мокрый асфальт
      drawRain();          // потом дождь
      drawFog();           // туман поверх
      drawGlassDrops();    // капли на стекле сверху

      requestAnimationFrame(draw);
    }

    draw();
  }

  initViceRain();
  console.log('[Vice City Rainy Night] Дождливая ночь активирована.');
})();
